async (page) => {
  // Get all release entries from the history list
  const releases = await page.locator('.release-timeline > li').all();
  const totalCount = releases.length;

  // Get the first (latest) release
  const latest = releases[0];
  const latestText = await latest.textContent();

  // Get the last (oldest visible) release
  const oldest = releases[releases.length - 1];
  const oldestText = await oldest.textContent();

  // Check if latest is a pre-release (contains beta, alpha, rc, etc.)
  const isPrerelease = /alpha|beta|rc|\.dev/i.test(latestText);

  return {
    totalCount,
    latestText: latestText.trim(),
    oldestText: oldestText.trim(),
    isPrerelease
  };
}

