async (page) => {
  // Let's scroll to the bottom to ensure all releases are loaded
  await page.evaluate(() => {
    const timeline = document.querySelector('div.release-timeline');
    if (timeline) {
      timeline.scrollIntoView();
    }
  });

  await page.waitForTimeout(1000);

  // Now get all links again
  const allLinks = await page.locator('div.release-timeline a[href^="/project/requests/"]').all();
  const total = allLinks.length;

  // Last link (oldest)
  const lastLink = allLinks[total - 1];
  const lastText = (await lastLink.textContent()).trim();
  console.log('Oldest visible release text:', lastText);

  // Also check second to last
  const secondLastLink = allLinks[total - 2];
  const secondLastText = (await secondLastLink.textContent()).trim();
  console.log('Second oldest visible release text:', secondLastText);

  return { total, oldest: lastText };
}

